export interface RawProductionRow {
  date: string;       // Assumed column
  machine: string;    // Assumed column
  lotNumber: string;  // Assumed column
  batchNumber: string; // Assumed column
  stepNumber: number; // Column G (Index 6)
  timeValue: number;  // Column J (Index 9)
  tempValue: number;  // Column L (Index 11)
  [key: string]: any; // Catch-all for other original efficiency columns
}

export interface GroupedBatch {
  lotNumber: string;
  batchNumber: string;
  machine: string;
  date: string;
  mx: number; // Sum of all time values in batch
  steps: {
    [stepId: number]: {
      time: number;
      temp: number;
    };
  };
  efficiency: number; // Placeholder for existing logic
  originalRows: any[];
}

export enum MachineType {
  MIXER = 'Mixer',
  PREPARATION = 'Preparation Machine'
}

export interface FilterState {
  startDate: string;
  endDate: string;
  machine: string;
}

import { RawProductionRow, GroupedBatch } from '../types';

const GOOGLE_SHEET_URL = 'https://script.google.com/macros/s/AKfycbxEVrBCNinBpAM1pUMsn43rhGT_JaJAIY3CSnJI5mJX51ab_cSihT5BnFxZ2Zfx1VFGQw/exec';

/**
 * Fetches CSV data and parses it into typed rows.
 * Note: CSV mapping is based on the column indices specified in the prompt.
 */
export const fetchProductionData = async (): Promise<RawProductionRow[]> => {
  try {
    const response = await fetch(GOOGLE_SHEET_URL);
    if (!response.ok) throw new Error('Failed to fetch data');

    // Most Google Script macros return text/csv or a JSON wrapper. 
    // If it's raw text (CSV):
    const text = await response.text();

    // Simple CSV parser
    const rows = text.split('\n').filter(row => row.trim() !== '');
    if (rows.length < 2) return [];

    // Assuming first row is header
    const dataRows = rows.slice(1);

    return dataRows.map(row => {
      const cols = row.split(',').map(c => c.trim().replace(/^"|"$/g, ''));

      // Mappings based on request:
      // Column G (Step) -> index 6
      // Column J (Time) -> index 9
      // Column L (Temp) -> index 11
      // We assume common columns for Date, Machine, Lot, Batch based on typical sheets
      // Column A (Date) -> 0, Column B (Machine) -> 1, Column C (Lot) -> 2, Column D (Batch) -> 3

      return {
        date: cols[0] || '',
        machine: cols[1] || '',
        lotNumber: cols[2] || '',
        batchNumber: cols[3] || '',
        stepNumber: parseInt(cols[6]) || 0,
        timeValue: parseFloat(cols[9]) || 0,
        tempValue: parseFloat(cols[11]) || 0,
        originalData: cols // Keep reference for efficiency calculations
      };
    });
  } catch (error) {
    console.error('Data Fetch Error:', error);
    return [];
  }
};

/**
 * Processes raw rows into consolidated batch objects.
 */
export const processBatchData = (rows: RawProductionRow[]): GroupedBatch[] => {
  const groups: Record<string, GroupedBatch> = {};

  rows.forEach(row => {
    const key = `${row.lotNumber}-${row.batchNumber}`;

    if (!groups[key]) {
      groups[key] = {
        lotNumber: row.lotNumber,
        batchNumber: row.batchNumber,
        machine: row.machine,
        date: row.date,
        mx: 0,
        steps: {},
        efficiency: 0, // Logic for production efficiency can be added here
        originalRows: []
      };
    }

    const group = groups[key];
    group.mx += row.timeValue;
    group.steps[row.stepNumber] = {
      time: row.timeValue,
      temp: row.tempValue
    };
    group.originalRows.push(row);

    // Basic placeholder for efficiency: (Actual Time / Target Time)
    // In a real app, this would use the 'original logic' mentioned.
    group.efficiency = 100 - (group.mx / 10); 
  });

  return Object.values(groups);
};

