import { RawProductionRow, GroupedBatch, MachineType } from '../types';

const GOOGLE_SHEET_URL = 'https://script.google.com/macros/s/AKfycbxEVrBCNinBpAM1pUMsn43rhGT_JaJAIY3CSnJI5mJX51ab_cSihT5BnFxZ2Zfx1VFGQw/exec';

/**
 * Generates realistic mock data for demonstration purposes if the API is unreachable.
 */
const generateMockData = (): RawProductionRow[] => {
  const mockRows: RawProductionRow[] = [];
  const machines = [MachineType.MIXER, MachineType.PREPARATION];
  const startDate = new Date();
  startDate.setDate(startDate.getDate() - 5);

  for (let i = 0; i < 50; i++) {
    const lotNum = `LOT-${1000 + Math.floor(i / 5)}`;
    const batchNum = `B${(i % 5) + 1}`;
    const date = new Date(startDate);
    date.setDate(date.getDate() + Math.floor(i / 10));

    // Steps G (6), J (9), L (11)
    mockRows.push({
      date: date.toISOString().split('T')[0],
      machine: machines[i % 2],
      lotNumber: lotNum,
      batchNumber: batchNum,
      stepNumber: (i % 3) + 1,
      timeValue: 1.5 + Math.random() * 5,
      tempValue: 40 + Math.random() * 60,
    });
  }
  return mockRows;
};

/**
 * Robust CSV Line Splitter (handles commas within quotes)
 */
const splitCSVLine = (line: string): string[] => {
  const result = [];
  let current = '';
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const char = line[i];
    if (char === '"') inQuotes = !inQuotes;
    else if (char === ',' && !inQuotes) {
      result.push(current.trim());
      current = '';
    } else {
      current += char;
    }
  }
  result.push(current.trim());
  return result;
};

/**
 * Fetches CSV data with a fallback to mock data on network/CORS failure.
 */
export const fetchProductionData = async (): Promise<{ data: RawProductionRow[], isMock: boolean }> => {
  try {
    const response = await fetch(GOOGLE_SHEET_URL, {
      method: 'GET',
      mode: 'cors',
      cache: 'no-cache',
    });

    if (!response.ok) throw new Error('Network response was not ok');

    const text = await response.text();
    const lines = text.split(/\r?\n/).filter(line => line.trim() !== '');
    if (lines.length < 2) throw new Error('Empty or invalid CSV received');

    const dataRows = lines.slice(1);
    const parsed = dataRows.map(row => {
      const cols = splitCSVLine(row).map(c => c.replace(/^"|"$/g, ''));
      return {
        date: cols[0] || '',
        machine: cols[1] || '',
        lotNumber: cols[2] || '',
        batchNumber: cols[3] || '',
        stepNumber: parseInt(cols[6]) || 0,
        timeValue: parseFloat(cols[9]) || 0,
        tempValue: parseFloat(cols[11]) || 0,
      };
    });

    return { data: parsed, isMock: false };
  } catch (error) {
    console.warn('Data fetch failed, providing mock data. Error:', error);
    // On "Failed to fetch" (CORS/Network), return high-quality mock data
    return { data: generateMockData(), isMock: true };
  }
};

/**
 * Processes raw rows into consolidated batch objects.
 */
export const processBatchData = (rows: RawProductionRow[]): GroupedBatch[] => {
  const groups: Record<string, GroupedBatch> = {};

  rows.forEach(row => {
    const key = `${row.lotNumber}-${row.batchNumber}`;

    if (!groups[key]) {
      groups[key] = {
        lotNumber: row.lotNumber,
        batchNumber: row.batchNumber,
        machine: row.machine,
        date: row.date,
        mx: 0,
        steps: {},
        efficiency: 0,
        originalRows: []
      };
    }

    const group = groups[key];
    group.mx += row.timeValue;
    group.steps[row.stepNumber] = {
      time: row.timeValue,
      temp: row.tempValue
    };
    group.originalRows.push(row);

    // Efficiency logic: Target 15 mins per batch, subtract variance
    const targetTime = 15;
    group.efficiency = Math.max(0, Math.min(100, (targetTime / group.mx) * 100));
  });

  return Object.values(groups);
};

import React, { useState, useEffect, useCallback } from 'react';
import FilterSection from './components/FilterSection';
import ProductionTable from './components/ProductionTable';
import StatsOverview from './components/StatsOverview';
import { fetchProductionData, processBatchData } from './services/dataService';
import { FilterState, GroupedBatch } from './types';

const App: React.FC = () => {
  const [filters, setFilters] = useState<FilterState>({
    startDate: new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    endDate: new Date().toISOString().split('T')[0],
    machine: ''
  });

  const [isLoading, setIsLoading] = useState(false);
  const [isUsingMockData, setIsUsingMockData] = useState(false);
  const [allData, setAllData] = useState<GroupedBatch[]>([]);
  const [filteredData, setFilteredData] = useState<GroupedBatch[]>([]);
  const [error, setError] = useState<string | null>(null);

  const handleFetchData = async () => {
    setIsLoading(true);
    setError(null);
    try {
      const { data, isMock } = await fetchProductionData();
      const grouped = processBatchData(data);
      setAllData(grouped);
      setIsUsingMockData(isMock);
