/**
 * Generates realistic mock data if the API is unreachable.
 */
const generateMockData = (): RawProductionRow[] => {
  const mockRows: RawProductionRow[] = [];
  const machines = [MachineType.MIXER, MachineType.PREPARATION];
  const startDate = new Date();
  startDate.setDate(startDate.getDate() - 5);

  for (let i = 0; i < 60; i++) {
    const lotNum = `LOT-${2045 + Math.floor(i / 6)}`;
    const batchNum = `B${(i % 6) + 1}`;
    const date = new Date(startDate);
    date.setDate(date.getDate() + Math.floor(i / 12));

    mockRows.push({
      date: date.toISOString().split('T')[0],
      machine: machines[i % 2],
      lotNumber: lotNum,
      batchNumber: batchNum,
      stepNumber: (i % 4) + 1,
      timeValue: 2.0 + Math.random() * 8,
      tempValue: 35 + Math.random() * 55,
    });
  }
  return mockRows;
};

/**
 * Enhanced line splitter that handles quotes and multiple delimiters.
 */
const parseLine = (line: string, delimiter: string = ','): string[] => {
  const result = [];
  let current = '';
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const char = line[i];
    if (char === '"') inQuotes = !inQuotes;
    else if (char === delimiter && !inQuotes) {
      result.push(current.trim().replace(/^"|"$/g, ''));
      current = '';
    } else {
      current += char;
    }
  }
  result.push(current.trim().replace(/^"|"$/g, ''));
  return result;
};

/**
 * Fetches data from the Google Script.
 * Uses a simplified fetch to avoid CORS preflight issues.
 */
export const fetchProductionData = async (): Promise<{ data: RawProductionRow[], isMock: boolean }> => {
  try {
    // Simplified fetch to minimize CORS preflight triggers
    const response = await fetch(GOOGLE_SHEET_URL, {
      method: 'GET',
      redirect: 'follow',
    });

    if (!response.ok) throw new Error(`HTTP status ${response.status}`);

    const text = await response.text();
    const trimmedText = text.trim();

    // Check if response is actually JSON (some macros return JSON)
    if (trimmedText.startsWith('[') || trimmedText.startsWith('{')) {
      try {
        const jsonData = JSON.parse(trimmedText);
        const list = Array.isArray(jsonData) ? jsonData : (jsonData.data || []);
        return { 
          data: list.map((item: any) => ({
            date: item.date || item[0] || '',
            machine: item.machine || item[1] || '',
            lotNumber: item.lotNumber || item[2] || '',
            batchNumber: item.batchNumber || item[3] || '',
            stepNumber: parseInt(item.stepNumber || item[6]) || 0,
            timeValue: parseFloat(item.timeValue || item[9]) || 0,
            tempValue: parseFloat(item.tempValue || item[11]) || 0,
          })), 
          isMock: false 
        };
      } catch (e) {
        console.warn('JSON parse failed, falling back to CSV logic');
      }
    }

    // CSV Parsing Logic
    const lines = trimmedText.split(/\r?\n/).filter(line => line.trim() !== '');
    if (lines.length < 2) throw new Error('Insufficient data in CSV');

    // Detect delimiter (comma vs semicolon)
    const firstLine = lines[0];
    const delimiter = firstLine.includes(';') && !firstLine.includes(',') ? ';' : ',';

    const dataRows = lines.slice(1);
    const parsed = dataRows.map(row => {
      const cols = parseLine(row, delimiter);
      return {
        date: cols[0] || '',
        machine: cols[1] || '',
        lotNumber: cols[2] || '',
        batchNumber: cols[3] || '',
        stepNumber: parseInt(cols[6]) || 0,
        timeValue: parseFloat(cols[9]) || 0,
        tempValue: parseFloat(cols[11]) || 0,
      };
    });

    return { data: parsed, isMock: false };
  } catch (error) {
    console.error('Data Fetch Error:', error);
    // On failure, return mock data to keep the UI functional
    return { data: generateMockData(), isMock: true };
  }
};

/**
 * Aggregates steps into batches and calculates efficiency.
 */
export const processBatchData = (rows: RawProductionRow[]): GroupedBatch[] => {
  const groups: Record<string, GroupedBatch> = {};

  rows.forEach(row => {
    const key = `${row.lotNumber}-${row.batchNumber}`;

    if (!groups[key]) {
      groups[key] = {
        lotNumber: row.lotNumber,
        batchNumber: row.batchNumber,
        machine: row.machine,
        date: row.date,
        mx: 0,
        steps: {},
        efficiency: 0,
        originalRows: []
      };
    }

    const group = groups[key];
    group.mx += row.timeValue;
    group.steps[row.stepNumber] = {
      time: row.timeValue,
      temp: row.tempValue
    };
    group.originalRows.push(row);
  });

  // Post-process for efficiency
  const result = Object.values(groups);
  result.forEach(batch => {
    // Basic industrial logic: Target is 25 minutes total cycle
    const target = 25;
    batch.efficiency = Math.max(0, Math.min(100, (target / (batch.mx || 1)) * 100));
  });

  return result;
};

