import { RawProductionRow, GroupedBatch, MachineType } from '../types';

const GOOGLE_SHEET_URL = 'https://script.google.com/macros/s/AKfycbxEVrBCNinBpAM1pUMsn43rhGT_JaJAIY3CSnJI5mJX51ab_cSihT5BnFxZ2Zfx1VFGQw/exec';

const generateMockData = (): RawProductionRow[] => {
  const mockRows: RawProductionRow[] = [];
  const machines = [MachineType.MIXER, MachineType.PREPARATION];
  const today = new Date();

  for (let i = 0; i < 40; i++) {
    const lotNum = `LOT-${3000 + Math.floor(i / 4)}`;
    const batchNum = `B${(i % 4) + 1}`;
    const date = new Date(today);
    date.setDate(date.getDate() - Math.floor(i / 8));

    mockRows.push({
      date: date.toISOString(), // Column B placeholder
      machine: machines[i % 2],
      lotNumber: lotNum,
      batchNumber: batchNum,
      stepNumber: (i % 4) + 1, // Column G (Index 6)
      timeValue: 5 + Math.random() * 10, // Column J (Index 9)
      tempValue: 60 + Math.random() * 40, // Column L (Index 11)
    });
  }
  return mockRows;
};

export const fetchProductionData = async (): Promise<{ data: RawProductionRow[], isMock: boolean }> => {
  try {
    console.log('Fetching production data from:', GOOGLE_SHEET_URL);
    const response = await fetch(GOOGLE_SHEET_URL, { method: 'GET' });

    if (!response.ok) throw new Error(`HTTP Error: ${response.status}`);

    const rawResponse = await response.text();
    console.debug('Raw API Response Received:', rawResponse);

    let rows: any[][];
    try {
      rows = JSON.parse(rawResponse);
    } catch (e) {
      // If the macro returns raw CSV instead of JSON
      const lines = rawResponse.trim().split(/\r?\n/);
      rows = lines.map(line => line.split(',').map(c => c.trim().replace(/^"|"$/g, '')));
    }

    // Map to defined structure based on prompt columns
    // Headers are at rows[0], data starts at rows[1]
    const dataRows = rows.slice(1).map(cols => ({
      date: cols[1] || '',          // Column B (Index 1): Production Time
      machine: cols[0] || '',       // Column A (Index 0)
      lotNumber: cols[2] || '',     // Column C (Index 2)
      batchNumber: cols[5] || '',   // Column F (Index 5): Updated as per requirement
      stepNumber: parseInt(cols[6]) || 0, // Column G (Index 6): Step
      timeValue: parseFloat(cols[9]) || 0, // Column J (Index 9): Time
      tempValue: parseFloat(cols[11]) || 0, // Column L (Index 11): Temp
    }));

    return { data: dataRows, isMock: false };
  } catch (error) {
    console.warn('API Fetch failed, using mock data. Debug info:', error);
    return { data: generateMockData(), isMock: true };
  }
};

export const processBatchData = (rows: RawProductionRow[]): GroupedBatch[] => {
  const groups: Record<string, GroupedBatch> = {};

  rows.forEach(row => {
    // Group strictly by Lot Number and Batch Number
    const key = `${row.lotNumber}_${row.batchNumber}`;

    if (!groups[key]) {
      groups[key] = {
        lotNumber: row.lotNumber,
        batchNumber: row.batchNumber,
        machine: row.machine,
        date: row.date,
        mx: 0,
        steps: {},
        efficiency: 0,
        originalRows: []
      };
    }

    const group = groups[key];
    // Sum Time Values for MX calculation
    group.mx += row.timeValue;

    // Map time from J and temp from L to step G
    group.steps[row.stepNumber] = {
      time: row.timeValue,
      temp: row.tempValue
    };
    group.originalRows.push(row);
  });

  const batches = Object.values(groups);
  batches.forEach(b => {
    // Efficiency logic: Target 30 min sum
    const target = 30;
    b.efficiency = Math.min(100, (target / (b.mx || 1)) * 100);
  });

  return batches;
};

