/**
 * Optimized grouping function using a hash map.
 * Processes pre-filtered raw data to maximize performance.
 */
export const processBatchData = (rows: RawProductionRow[]): GroupedBatch[] => {
  console.time('grouping_processing');
  const groups: Record<string, GroupedBatch> = {};

  // single pass using hash map
  for (let i = 0; i < rows.length; i++) {
    const row = rows[i];
    const key = `${row.lotNumber}_${row.batchNumber}`;

    if (!groups[key]) {
      groups[key] = {
        lotNumber: row.lotNumber,
        batchNumber: row.batchNumber,
        machine: row.machine,
        date: row.date,
        mx: 0,
        steps: {},
        efficiency: 0,
        originalRows: []
      };
    }

    const group = groups[key];
    group.mx += row.timeValue;

    // Ensure we don't hit infinite cycles by checking step bounds if needed
    // Mapping J (time) and L (temp) via row properties
    if (row.stepNumber > 0 && row.stepNumber < 100) {
      group.steps[row.stepNumber] = {
        time: row.timeValue,
        temp: row.tempValue
      };
    }
    group.originalRows.push(row);
  }

  const batches = Object.values(groups);
  const target = 30;
  for (let j = 0; j < batches.length; j++) {
    const b = batches[j];
    b.efficiency = Math.min(100, (target / (b.mx || 1)) * 100);
  }

  console.timeEnd('grouping_processing');
  return batches;
};

